  };

  // ── Files app ──
  let filesWindow = null;
  let currentPath = '/';

  function getIcon(name, type) {
    if (type === 'folder') return '📁';
    const ext = name.split('.').pop().toLowerCase();
    const icons = { txt: '📄', md: '📝', list: '📋', iso: '💿', tar: '📦', gz: '📦', m3u: '🎵', png: '🖼️', jpg: '🖼️', sh: '⚙️', conf: '⚙️', cfg: '⚙️' };
    return icons[ext] || '📄';
  }

  function renderFiles() {
    const list = document.querySelector('.files-list');
    if (!list) return;
    list.innerHTML = '';
    const entries = fs[currentPath] || [];
    // Sort: folders first, then files
    const sorted = [...entries].sort((a, b) => {
      if (a.type !== b.type) return a.type === 'folder' ? -1 : 1;
      return a.name.localeCompare(b.name);
    });

    for (const entry of sorted) {
      const item = document.createElement('div');
      item.className = 'fs-item';
      item.innerHTML = `
        <span class="fs-icon">${getIcon(entry.name, entry.type)}</span>
        <span class="fs-name">${entry.name}</span>
        ${entry.size ? `<span class="fs-size">${entry.size}</span>` : ''}
      `;

      if (entry.type === 'folder') {
        item.addEventListener('dblclick', () => {
          currentPath = currentPath === '/' ? '/' + entry.name : currentPath + '/' + entry.name;
          renderFiles();
          const pathEl = document.getElementById('files-path');
          if (pathEl) pathEl.value = currentPath;
        });
      }

      list.appendChild(item);
    }
  }

  function openFiles() {
    if (filesWindow && !filesWindow.closed) {
      filesWindow.focus();
      return;
    }
    const container = document.getElementById('windows-container');
    const win = document.createElement('div');
    win.id = 'files-window';
    win.className = 'app-window';
    win.innerHTML = `
      <div class="win-titlebar" data-drag="true">
        <span class="title">Files</span>
        <div class="win-controls">
          <button class="win-close-btn win-close" title="Close">✕</button>
        </div>
      </div>
      <div class="win-body">
        <div class="files-toolbar">
          <button id="files-up" title="Go up">↑</button>
          <input type="text" id="files-path" value="/" readonly />
        </div>
        <div class="files-list"></div>
      </div>
    `;
    container.appendChild(win);

    // Close button
    win.querySelector('.win-close').addEventListener('click', () => {
      win.remove();
      filesWindow = null;
      updateDockDots();
    });

    // Up navigation
    document.getElementById('files-up').addEventListener('click', () => {
      if (currentPath === '/') return;
      currentPath = currentPath.replace(/\/[^/]+$/, '') || '/';
      renderFiles();
      const pathEl = document.getElementById('files-path');
      if (pathEl) pathEl.value = currentPath;
    });

    // Make draggable
    makeDraggable(win);

    filesWindow = win;
    updateDockDots();
    renderFiles();
  }

  function closeFiles() {
    const w = document.getElementById('files-window');
    if (w) w.remove();
    filesWindow = null;
    updateDockDots();
  }

  // ── Notepad app ──
  let notepadWindow = null;
  const STORAGE_KEY = 'notepad-tabs';

  function loadTabs() {
    try {
      return JSON.parse(localStorage.getItem(STORAGE_KEY)) || [];
    } catch { return []; }
  }

  function saveTabs(tabs) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
  }

  let activeTabIndex = 0;

  function renderNotepad() {
    const tabsContainer = document.getElementById('tabs');
    if (!tabsContainer) return;
    const tabs = loadTabs();
    tabsContainer.innerHTML = '';
    tabs.forEach((tab, i) => {
      const el = document.createElement('div');
      el.className = 'tab' + (i === activeTabIndex ? ' active' : '');
      const name = tab.name || `Untitled ${i + 1}`;
      el.innerHTML = `<span class="tab-label">${name}</span><button class="tab-close" data-idx="${i}">✕</button>`;

      el.addEventListener('click', (e) => {
        if (e.target.classList.contains('tab-close')) return;
        activeTabIndex = i;
        renderNotepad();
        const editor = document.getElementById('editor');
        if (editor) editor.value = tabs[i].content || '';
      });

      el.querySelector('.tab-close').addEventListener('click', () => {
        const updated = loadTabs();
        updated.splice(i, 1);
        saveTabs(updated);
        if (activeTabIndex >= updated.length && updated.length > 0) activeTabIndex = updated.length - 1;
        else if (updated.length === 0) activeTabIndex = 0;
        renderNotepad();
        const editor = document.getElementById('editor');
        if (editor && updated.length > 0) editor.value = updated[activeTabIndex].content || '';
      });

      tabsContainer.appendChild(el);
    });

    // Update editor content
    const editor = document.getElementById('editor');
    if (editor) {
      const tabs = loadTabs();
      if (tabs[activeTabIndex]) {
        editor.value = tabs[activeTabIndex].content || '';
      } else {
        editor.value = '';
      }
    }
  }

  function openNotepad() {
    if (notepadWindow && !notepadWindow.closed) {
      notepadWindow.focus();
      return;
    }

    // Ensure at least one tab exists
    let tabs = loadTabs();
    if (tabs.length === 0) {
      tabs.push({ name: 'Untitled', content: '' });
      saveTabs(tabs);
    }
    activeTabIndex = Math.min(activeTabIndex, tabs.length - 1);

    const container = document.getElementById('windows-container');
    const win = document.createElement('div');
    win.id = 'notepad-window';
    win.className = 'app-window';
    win.innerHTML = `
      <div class="win-titlebar" data-drag="true">
        <span class="title">Text Editor</span>
        <div class="win-controls">
          <button class="win-close-btn win-close" title="Close">✕</button>
        </div>
      </div>
      <div class="notepad-tabs-bar">
        <button id="new-tab" title="New tab">+</button>
        <div id="tabs"></div>
      </div>
      <div id="editor-wrap">
        <textarea id="editor" spellcheck="false"></textarea>
      </div>
    `;
    container.appendChild(win);

    // Close button
    win.querySelector('.win-close').addEventListener('click', () => {
      saveTabs(loadTabs());
      win.remove();
      notepadWindow = null;
      updateDockDots();
    });

    // New tab
    document.getElementById('new-tab').addEventListener('click', () => {
      const tabs = loadTabs();
      const idx = tabs.length + 1;
      tabs.push({ name: `Untitled ${idx}`, content: '' });
      saveTabs(tabs);
      activeTabIndex = tabs.length - 1;
      renderNotepad();
    });

    // Editor input → persist
    document.getElementById('editor').addEventListener('input', () => {
      const editor = document.getElementById('editor');
      const tabs = loadTabs();
      if (tabs[activeTabIndex]) {
        tabs[activeTabIndex].content = editor.value;
        saveTabs(tabs);
      }
    });

    // Tab key in textarea inserts spaces
    document.getElementById('editor').addEventListener('keydown', (e) => {
      if (e.key === 'Tab') {
        e.preventDefault();
        const ta = e.target;
        const start = ta.selectionStart;
        const end = ta.selectionEnd;
        ta.value = ta.value.substring(0, start) + '  ' + ta.value.substring(end);
        ta.selectionStart = ta.selectionEnd = start + 2;
      }
    });

    makeDraggable(win);

    notepadWindow = win;
    updateDockDots();
    renderNotepad();
  }

  function closeNotepad() {
    saveTabs(loadTabs());
    const w = document.getElementById('notepad-window');
    if (w) w.remove();
    notepadWindow = null;
    updateDockDots();
  }

  // ── Dock dots ──
  function updateDockDots() {
    const filesBtn = document.getElementById('open-files');
    const notesBtn = document.getElementById('open-notepad');
    if (filesWindow) filesBtn.classList.add('active'); else filesBtn.classList.remove('active');
    if (notepadWindow) notesBtn.classList.add('active'); else notesBtn.classList.remove('active');
  }

  // ── Draggable windows ──
  function makeDraggable(win) {
    const titlebar = win.querySelector('.win-titlebar');
    let isDragging = false, startX, startY, origX, origY;

    titlebar.addEventListener('mousedown', (e) => {
      if (e.target.classList.contains('win-close') || e.target.closest('.win-controls')) return;
      isDragging = true;
      startX = e.clientX;
      startY = e.clientY;
      const rect = win.getBoundingClientRect();
      origX = rect.left;
      origY = rect.top;
      win.classList.add('dragging');

      // Bring to front
      document.querySelectorAll('.app-window').forEach(w => w.style.zIndex = 50);
      win.style.zIndex = 60;

      e.preventDefault();
    });

    document.addEventListener('mousemove', (e) => {
      if (!isDragging) return;
      const dx = e.clientX - startX;
      const dy = e.clientY - startY;
      win.style.left = (origX + dx) + 'px';
      win.style.top = (origY + dy) + 'px';
    });

    document.addEventListener('mouseup', () => {
      if (isDragging) {
        isDragging = false;
        win.classList.remove('dragging');
      }
    });
  }

  // ── Launcher buttons ──
  document.getElementById('open-files').addEventListener('click', openFiles);
  document.getElementById('open-notepad').addEventListener('click', openNotepad);

})();
</script>
</body>
</html>
